comp:
uniform sampler2D sampler_rand00;
 shader_body { 
  vec4 tmpvar_1;
  tmpvar_1.w = 1.0;
  tmpvar_1.xyz = (1.0 - pow (texture (sampler_main, uv).xyz, texture (sampler_rand00, (uv + vec2(1.0, 0.0))).xyz));
  ret = tmpvar_1.xyz;
 }
